class Solution(object):
    def processStr(self, s, k):
        # Track length after each operation
        lengths = [0]  # lengths[i] = length after processing s[0..i-1]
        cur_len = 0
        for c in s:
            if c.islower():
                cur_len += 1
            elif c == '*':
                cur_len = max(0, cur_len - 1)
            elif c == '#':
                cur_len *= 2
            elif c == '%':
                pass  # length unchanged
            lengths.append(cur_len)
        if k >= lengths[-1]:
            return '.'
        # Walk backwards to find k-th character
        pos = k  # 0-indexed position we're looking for
        for i in range(len(s) - 1, -1, -1):
            c = s[i]
            if c.islower():
                # This char was appended at position lengths[i] (0-indexed)
                if pos == lengths[i]:
                    return c
                # else pos < lengths[i], continue
            elif c == '*':
                # Last char was removed; if pos == lengths[i+1]-1, it's gone (but we started with valid pos)
                # Actually: lengths[i+1] = lengths[i] - 1, so pos < lengths[i+1] = lengths[i]-1
                # pos is valid in result after *, which has length lengths[i]-1
                # Before *, the string had length lengths[i]; pos is unchanged
                pass
            elif c == '#':
                # length doubled: lengths[i+1] = 2 * lengths[i]
                # pos in doubled string maps to pos % lengths[i] in original
                pos = pos % lengths[i]
            elif c == '%':
                # reversed: pos in reversed string maps to lengths[i]-1-pos in original
                pos = lengths[i] - 1 - pos
        return '.'  # should not reach here
